   300		width := t.emulator.Width()
   301		altScreen := t.emulator.IsAltScreen()
   302	
   303		// Start from a known pen: reset all SGR attributes.
   304		b.WriteString("\x1b[0m")
   305	
   306		// Match the screen buffer the program is currently driving. A TUI in the
   307		// alternate screen owns the whole viewport; a normal shell session keeps
   308		// its scrollback. Setting the mode explicitly means a reconnecting client
   309		// (which may be in either state) is forced into the correct one.
   310		if altScreen {
   311			b.WriteString("\x1b[?1049h")
   312		} else {
   313			b.WriteString("\x1b[?1049l")
   314			// For a normal-screen session, replay the scrolled-off history first so
   315			// the client can scroll back. These lines flow into the terminal's own
   316			// scrollback as the visible grid is painted over them below.
   317			if sb := t.emulator.Scrollback(); sb != nil {
   318				for _, line := range sb.Lines() {
   319					b.WriteString(uv.Line(line).Render())
   320					b.WriteString("\r\n")
   321				}
   322			}
   323		}
   324	
   325		// Clear the viewport so stale content from the client's prior state cannot
   326		// bleed through, then paint each visible row at an absolute position. Using
   327		// explicit cursor addressing (rather than relying on newline/auto-wrap flow)
   328		// keeps the repaint exact regardless of the receiving terminal's wrap mode.
   329		b.WriteString("\x1b[2J")
   330		rows := strings.Split(t.emulator.Render(), "\n")
   331		for y, row := range rows {
   332			fmt.Fprintf(&b, "\x1b[%d;1H", y+1)
   333			// Render() trims trailing blanks per row; clear to end-of-line so any
   334			// residue past the content is wiped, then write the row.
   335			if width > 0 {
   336				b.WriteString("\x1b[K")
   337			}
   338			b.WriteString(row)
   339		}
   340	
   341		// Reset the pen again before restoring the cursor so the live stream that
   342		// follows starts from default attributes, then place the cursor exactly
   343		// where the program left it (emulator coordinates are 0-based).
   344		b.WriteString("\x1b[0m")
   345		pos := t.emulator.CursorPosition()
   346		fmt.Fprintf(&b, "\x1b[%d;%dH", pos.Y+1, pos.X+1)
   347	
   348		return []byte(b.String())
   349	}
