   322	    pane size=1 borderless=true {
   323	        plugin location="tab-bar"
   324	    }
   325	    pane command="bash" cwd=%s {
   326	        args "-c" %s
   327	    }
   328	    pane size=1 borderless=true {
   329	        plugin location="status-bar"
   330	    }
   331	}
