    46	func TestEnsureIsIdempotent(t *testing.T) {
    47		home := t.TempDir()
    48		t.Setenv("HOME", home)
    49	
    50		path, err := Ensure()
    51		if err != nil {
    52			t.Fatalf("first Ensure: %v", err)
    53		}
    54		info, err := os.Stat(path)
    55		if err != nil {
    56			t.Fatalf("stat: %v", err)
    57		}
    58		first := info.ModTime()
    59	
    60		again, err := Ensure()
    61		if err != nil {
    62			t.Fatalf("second Ensure: %v", err)
    63		}
    64		if again != path {
    65			t.Fatalf("path changed: %q != %q", again, path)
    66		}
    67		info2, err := os.Stat(path)
    68		if err != nil {
    69			t.Fatalf("stat after second Ensure: %v", err)
    70		}
    71		// Unchanged content must not be rewritten, so the mtime stays put.
    72		if !info2.ModTime().Equal(first) {
    73			t.Errorf("config rewritten despite matching content: %v -> %v", first, info2.ModTime())
    74		}
    75	}
